ai.tldr:
{
    "affiliations": [],
    "keywords_raw": ["stochastic nonconvex optimization", "adaptive regularization", "trust region methods", "decision-dependent noise", "adaptive sampling", "almost sure iteration complexity", "sample complexity", "Reg-ASTRO"],
    "keywords_normalized": ["stochastic optimization", "nonconvex optimization", "trust region methods", "adaptive regularization", "sample complexity", "decision-dependent noise"],
    "zh": {
        "tldr": "提出Reg-ASTRO算法，一种结合自适应正则化的随机非凸优化信任域方法，在决策依赖噪声下实现几乎确定的$\tilde{\mathcal{O}}(ε^{-1.5})$迭代复杂度。",
        "motivation": "传统随机优化方法在处理决策依赖噪声、无界支撑的非凸问题时，迭代和样本复杂度较高，需要更高效的算法。",
        "method": "在ASTRO框架中引入自适应正则化局部模型，通过自适应采样使估计精度与平稳性度量对齐，接近平稳点时提高采样精度。",
        "result": "Reg-ASTRO达到几乎确定$\tilde{\mathcal{O}}(ε^{-1.5})$迭代复杂度和$\tilde{\mathcal{O}}(ε^{-4.5})$样本复杂度，在更强正则条件下可提升至$\tilde{\mathcal{O}}(ε^{-3.5})$，数值实验优于一阶方法。",
        "help_to_user": "为处理决策依赖噪声的非凸随机优化提供了理论保证更强的高效算法框架。",
        "idea_spark": {
            "transferable": "自适应正则化与信任域半径的耦合机制可迁移至其他随机二阶优化算法。",
            "idea": "将自适应采样准则与局部模型的正则化强度动态关联，以平衡估计误差与计算成本。",
            "risk": "理论分析依赖于噪声的次指数尾分布假设，实际应用中若噪声分布不满足可能影响性能。",
            "inspiration": "启发在随机优化中联合设计采样策略与模型正则化，以应对复杂噪声环境。"
        }
    },
    "en": {
        "tldr": "Proposes Reg-ASTRO, a stochastic nonconvex optimization algorithm combining adaptive regularization with trust region methods, achieving almost sure $\tilde{\mathcal{O}}(ε^{-1.5})$ iteration complexity under decision-dependent noise.",
        "motivation": "Existing stochastic optimization methods suffer from high iteration and sample complexity for nonconvex problems with decision-dependent noise and unbounded support, necessitating more efficient algorithms.",
        "method": "Augments the ASTRO framework with an adaptively regularized local model, using adaptive sampling to align estimation precision with a stationarity measure—higher accuracy required near stationary points.",
        "result": "Reg-ASTRO achieves almost sure $\tilde{\mathcal{O}}(ε^{-1.5})$ iteration complexity and $\tilde{\mathcal{O}}(ε^{-4.5})$ sample complexity, improving to $\tilde{\mathcal{O}}(ε^{-3.5})$ under stronger regularity conditions, outperforming first-order methods in numerical experiments.",
        "help_to_user": "Provides an efficient algorithm framework with stronger theoretical guarantees for stochastic nonconvex optimization with decision-dependent noise.",
        "idea_spark": {
            "transferable": "The coupling mechanism between adaptive regularization and trust-region radius can be transferred to other stochastic second-order optimization algorithms.",
            "idea": "Dynamically link adaptive sampling criteria with the regularization strength of the local model to balance estimation error and computational cost.",
            "risk": "Theoretical analysis relies on the subexponential tail assumption of noise; performance may degrade if real-world noise violates this.",
            "inspiration": "Inspires the joint design of sampling strategies and model regularization in stochastic optimization to handle complex noise environments."
        }
    }
}

